### Authentication Patterns

Next.js supports several authentication strategies:

- **Session-based**: Store session in cookies/database
- **JWT-based**: JSON Web Tokens for stateless auth
- **OAuth**: Google, GitHub, etc. via NextAuth.js
- **Magic Links**: Passwordless email auth

### NextAuth.js (Auth.js)

```bash
npm install next-auth
```

### Basic Setup

```jsx
// pages/api/auth/[...nextauth].js
import NextAuth from 'next-auth';
import GoogleProvider from 'next-auth/providers/google';

export default NextAuth({
  providers: [
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID,
      clientSecret: process.env.GOOGLE_CLIENT_SECRET,
    }),
  ],
  secret: process.env.NEXTAUTH_SECRET,
});
```

### Session Management

Access session in client components:

```jsx
'use client';

import { useSession, signIn, signOut } from 'next-auth/react';

export default function AuthButton() {
  const { data: session } = useSession();

  if (session) {
    return (
      <div>
        <p>Signed in as {session.user.email}</p>
        <button onClick={() => signOut()}>Sign out</button>
      </div>
    );
  }

  return <button onClick={() => signIn()}>Sign in</button>;
}
```

Wrap the app with a SessionProvider:

```jsx
// pages/_app.js
import { SessionProvider } from 'next-auth/react';

export default function App({ Component, pageProps: { session, ...pageProps } }) {
  return (
    <SessionProvider session={session}>
      <Component {...pageProps} />
    </SessionProvider>
  );
}
```

### Protected Routes

Server-side protection with getServerSideProps:

```jsx
export async function getServerSideProps(context) {
  const session = await getSession(context);

  if (!session) {
    return {
      redirect: { destination: '/api/auth/signin', permanent: false },
    };
  }

  return { props: { session } };
}
```

### API Route Protection

```jsx
import { getServerSession } from 'next-auth';
import { authOptions } from './auth/[...nextauth]';

export default async function handler(req, res) {
  const session = await getServerSession(req, res, authOptions);

  if (!session) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  return res.status(200).json({ user: session.user });
}
```

### Middleware Auth

```jsx
// middleware.js
import { getToken } from 'next-auth/jwt';
import { NextResponse } from 'next/server';

export async function middleware(req) {
  const token = await getToken({ req, secret: process.env.NEXTAUTH_SECRET });

  if (!token) {
    return NextResponse.redirect(new URL('/api/auth/signin', req.url));
  }

  return NextResponse.next();
}

export const config = { matcher: ['/dashboard/:path*'] };
```

